<div data-fieldname="items" data-fieldtype="Table" class="items-table-wrapper">
    {% set currency_symbol = frappe.db.get_value('Currency', doc.currency, 'symbol') or "" %}

    {# Prefetch Join #}
    {% set tax_data_list = frappe.db.sql("""
        SELECT 
            child.parent as template_name, 
            child.tax_rate, 
            parent.custom_code
        FROM 
            `tabItem Tax Template Detail` child
        JOIN 
            `tabItem Tax Template` parent ON child.parent = parent.name
        WHERE 
            child.idx = 1
    """, as_dict=1) %}

    {% set tax_map = {} %}
    {% for row in tax_data_list %}
        {% set _ = tax_map.update({row.template_name: row}) %}
    {% endfor %}

    <table class="table table-bordered table-condensed">
        <thead>
            <tr>
                <th style="width: 30px" class="table-sr">Sr</th>
                <th style="width: auto;">Item & Description</th>
                <th style="width: 75px;">Taxes</th>
                <th style="width: 70px;">Qty</th>
                <th style="width: 90px;" class="text-right">Price</th>
                <th style="width: 100px;" class="text-right">Excl. Tax</th>
                <th style="width: 100px;" class="text-right">Total</th>
            </tr>
        </thead>
        <tbody>
            <!--<tr style="background-color: #fff9f9;">-->
            <!--    <td class="table-sr">123</td>-->
            <!--    <td>-->
            <!--        <strong>ABCD-ABCD-ABCD-ABCD-123456</strong>-->
            <!--        <small style="font-weight: normal; color: #555;">-->
            <!--            This is a long description to test how many lines of text can fit before it pushes the row height too far. We are checking for word-wrap and line-height consistency.-->
            <!--        </small>-->
            <!--    </td>-->
            <!--    <td>-->
            <!--        XABCD @ 12%-->
            <!--    </td>-->
            <!--    <td class="text-right">-->
            <!--        123,123.00 ABCD-->
            <!--    </td>-->
            <!--    <td class="text-right">{{ currency_symbol }} 10,123,123.12</td>-->
            <!--    <td class="text-right">{{ currency_symbol }} 10,123,123.12</td>-->
            <!--    <td class="text-right">{{ currency_symbol }} 1,000,123,123.12</td>-->
            <!--</tr>-->

            {% for item in doc.items %}
                {% set tax_info = tax_map.get(item.item_tax_template) or {} %}
                {# Use |int filter to remove decimals #}
                {% set tax_percent = (tax_info.tax_rate | int) if tax_info.tax_rate else 0 %}
                {% set tax_code = tax_info.custom_code or "" %}
                {% set net_amount = item.amount / (1 + (tax_percent/100)) %}

                <tr>
                    <td class="table-sr">{{ loop.index }}</td>
                    <td>
                        <strong>{{ item.item_code }}</strong>
                        {% if item.item_code != item.description %}
                            <small style="font-weight: normal; color: #555;">{{ item.description }}</small>
                        {% endif %}
                    </td>
                    <td>
                        {{ tax_code }} @ {{ tax_percent }}%
                    </td>
                    <td class="text-right">
                        {{ item.qty }} {{ item.uom }}
                    </td>
                    <td class="text-right">{{ currency_symbol }} {{ "{:,.2f}".format(item.rate) }}</td>
                    <td class="text-right">{{ currency_symbol }} {{ "{:,.2f}".format(net_amount) }}</td>
                    <td class="text-right">{{ currency_symbol }} {{ "{:,.2f}".format(item.amount) }}</td>
                </tr>
            {% endfor %}
        </tbody>
    </table>
